import{_ as t,o as n,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"42A. Permanent Night Shift","description":"","frontmatter":{"title":"42A. Permanent Night Shift","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/42A-permanent-night-shift.md","filePath":"ebas/nurses-midwives/hours-of-work/42A-permanent-night-shift.md"}'),r={name:"ebas/nurses-midwives/hours-of-work/42A-permanent-night-shift.md"};function i(a,e,h,p,l,m){return n(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_42a-permanent-night-shift" tabindex="-1">42A. Permanent Night Shift <a class="header-anchor" href="#_42a-permanent-night-shift" aria-label="Permalink to &quot;42A. Permanent Night Shift&quot;">​</a></h1><p>Note: This clause does not apply to casual Employees. It is the intent of this provision to maximise the use of permanent night shift employees.</p><p><strong>42A.1</strong> Permanent Night Shift Employment</p><p><strong>(a)</strong> In this clause, a permanent night shift employee means a full or part-time Employee who only works on night shift subject to the provisions of clause 42A.6.</p><p><strong>(b)</strong> Utilisation of permanent night shift employees will be the preferred approach to staffing at night wherever possible.</p><p><strong>42A.2</strong> Permanent Night Shift Employment – Employee Request</p><p><strong>(a)</strong> An Employee may make a written request to work permanent night shift and an Employer may only refuse on reasonable business grounds.</p><p><strong>(b)</strong> Where an Employee makes a written request, the Employer will respond in writing within 21 days.</p><p><strong>(c)</strong> Where an Employer proposes to refuse the request on reasonable business grounds, the Employer will notify the Employee in writing of those reasonable business grounds and will offer to meet with the Employee to discuss the request before a decision is made.</p><p><strong>42A.3</strong> Permanent Night Shift Employment – Transitional 1 July 2024 to 30 September 2024</p><p><strong>(a)</strong> With respect to wards or units with a night shift, the Employer will advise Employees who, in the previous 12 months or prior to commencing any period of extended leave:</p><p><strong>(i)</strong> were working as permanent night shift employees as defined at clause 42A.1 that they will be appointed as permanent night shift employees by 30 September 2024, unless they indicate they do not wish to be so appointed.</p><p><strong>(ii)</strong> were working as permanent night shift employees as defined at clause 42A.1 as part of a temporary variation, flexible work arrangement or comparable situation (“the arrangement”) they will be appointed as permanent night shift for the duration of the arrangement in respect to that ward or unit.</p><p><strong>(iii)</strong> worked night shift other than as a permanent night shift employee (i.e. worked night shifts and other shifts) to express an interest in continuing to work night shifts, and the amount of night shift they wish to continue working.</p><p><strong>(b)</strong> Employees at (iii) above will, where practicable, be offered night shifts in accordance with their expressed amount of desired night shift, in respect to that ward or unit.</p><p><strong>(c)</strong> Following the process described at subclause 42A.3(a), the Employer will seek expressions of interest from Employees with respect to the remaining night shifts</p><p>necessary to meet the night shift staffing requirements for that ward or unit by 31 August 2024.</p><p><strong>(d)</strong> In responding to expressions of interest, subject to any skill mix requirements, full or part time staff for whom the ward is their Base Ward will be preferred in determining permanent night shift status.</p><p><strong>(e)</strong> The Employer will provide progress reports to the WIC of progress in implementing this clause 42A.3.</p><p><strong>42A.4</strong> Post transition - Permanent Night Shift Employment Vacancy</p><p>Where a vacancy (whether permanent or temporary) on night shift occurs after 30 August 2024, the Employer will seek to fill it with a permanent night shift employee.</p><p><strong>42A.5</strong> Provision of education to permanent night shift employees</p><p><strong>(a)</strong> Wherever practicable, permanent night shift employees will be offered education during their night shift.</p><p><strong>(b)</strong> Where this is not practicable and it is necessary to roster the Employee to shifts other than night shift for the purpose of providing education, this will occur without loss of income to the Employee.</p><p><strong>(c)</strong> Nothing in this clause 42A is intended to alter an Employer&#39;s rights regarding undertaking performance management in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/15-managing-conduct-and-performance.html">clause 15</a> to support Employees. Performance management has the same meaning as set out at subclauses 15.7(b) and (c) of this Agreement.</p><p><strong>42A.6</strong> Other provisions</p><p><strong>(a)</strong> Where an Employer seeks to end an Employee’s status as a permanent night shift employee, the provisions of <a href="/eba/ebas/nurses-midwives/consultation-disputes/11A-consultation-about-changes-to-rosters-or-hours-of-work.html">clause 11A</a> shall apply and a notice period of not less than 8 weeks will be provided.</p><p><strong>(b)</strong> An Employee who is a permanent night shift worker must have a minimum 47 hours break before working other shifts unless requested by the Employer to return earlier.</p><p><strong>42A.7</strong> Review</p><p>The Employers will work with the ANMF to evaluate the changes above to ensure there are no unintended consequences, with reports being provided to the WIC.</p><p>Plain language terms: night duty, permanent nights.</p>',31)])])}const u=t(r,[["render",i]]);export{f as __pageData,u as default};
